// Milestone target durations (days) per stage
// Edit these to match your onboarding schedule
const MILESTONE_TARGETS = {
  'Kickoff Scheduled':    3,
  'Technical Setup':      7,
  'Integration Complete': 14,
  'Training Done':        21,
  'Go-Live':              30
};

// Map from HubSpot stage internal names to your display names
// Update these to match your HubSpot stage IDs
const STAGE_FIELD_MAP = {
  'Kickoff Scheduled':    'hs_date_entered_kickoff_scheduled',
  'Technical Setup':      'hs_date_entered_technical_setup',
  'Integration Complete': 'hs_date_entered_integration_complete',
  'Training Done':        'hs_date_entered_training_done',
  'Go-Live':              'hs_date_entered_go_live'
};

const results = [];
const today = new Date();

for (const item of $input.all()) {
  const deal = item.json;
  const props = deal.properties || deal; // handle both formats

  const stageName = props.dealstage || 'Unknown Stage';
  const dealName = props.dealname || 'Unnamed Deal';
  const ownerId = props.hubspot_owner_id || '';

  // Find how long they've been in current stage
  let daysInStage = null;
  const stageEnteredField = STAGE_FIELD_MAP[stageName];
  if (stageEnteredField && props[stageEnteredField]) {
    const enteredDate = new Date(props[stageEnteredField]);
    daysInStage = Math.floor((today - enteredDate) / (1000 * 60 * 60 * 24));
  } else if (props.hs_lastmodifieddate) {
    // Fallback: use last modified date
    const modified = new Date(props.hs_lastmodifieddate);
    daysInStage = Math.floor((today - modified) / (1000 * 60 * 60 * 24));
  }

  const targetDays = MILESTONE_TARGETS[stageName] || 7;
  const isBehind = daysInStage !== null && daysInStage > targetDays;
  const daysOverdue = isBehind ? daysInStage - targetDays : 0;

  // Determine next step nudge based on current stage
  const nudgeMessages = {
    'Kickoff Scheduled':    'We noticed your kickoff hasn\'t been scheduled yet. Please book a 30-min call with your CSM using this link: [CALENDAR_LINK]',
    'Technical Setup':      'Your technical setup is taking a bit longer than expected. Please review the setup guide and ensure your API credentials are configured.',
    'Integration Complete':  'Your integration step is overdue. Please connect to our integration wizard or reach out to support@yourcompany.com.',
    'Training Done':         'Your training milestone is pending. Join our next live onboarding session: [TRAINING_LINK]',
    'Go-Live':               'You\'re almost there! Please review your go-live checklist and confirm with your CSM when you\'re ready.'
  };
  const nudge = nudgeMessages[stageName] || 'Please connect with your CSM to unblock your onboarding.';

  results.push({
    json: {
      dealId: deal.id || props.hs_object_id,
      dealName,
      stageName,
      daysInStage,
      targetDays,
      isBehind,
      daysOverdue,
      ownerId,
      contactEmail: props.contact_email || '',
      contactFirstName: props.contact_firstname || 'there',
      nudgeMessage: nudge,
      hsLink: `https://app.hubspot.com/contacts/YOUR_PORTAL_ID/deal/${deal.id}`
    }
  });
}

// Only return behind-schedule deals
return results.filter(r => r.json.isBehind);
